/**
 * Cocktail Sort implementation.
 * Repeatedly steps through the list in both directions, comparing adjacent elements 
 * and swapping them if they are in the wrong order.
 */
object CocktailSort {
    fun sort(arr: IntArray): IntArray {
        if (arr.size <= 1) {
            return arr.copyOf()
        }

        val result = arr.copyOf()
        val n = result.size
        var start = 0
        var end = n - 1
        var swapped = true

        while (swapped) {
            swapped = false

            // Forward pass
            for (i in start until end) {
                if (result[i] > result[i + 1]) {
                    val temp = result[i]
                    result[i] = result[i + 1]
                    result[i + 1] = temp
                    swapped = true
                }
            }

            if (!swapped) {
                break
            }

            swapped = false
            end--

            // Backward pass
            for (i in end - 1 downTo start) {
                if (result[i] > result[i + 1]) {
                    val temp = result[i]
                    result[i] = result[i + 1]
                    result[i + 1] = temp
                    swapped = true
                }
            }

            start++
        }

        return result
    }
}

/**
 * Cocktail Sort implementation.
 * Repeatedly steps through the list in both directions, comparing adjacent elements 
 * and swapping them if they are in the wrong order.
 */
pub fn cocktail_sort(arr: &[i32]) -> Vec<i32> {
    let mut result = arr.to_vec();
    let n = result.len();

    if n <= 1 {
        return result;
    }

    let mut start = 0;
    let mut end = n - 1;
    let mut swapped = true;

    while swapped {
        swapped = false;

        // Forward pass
        for i in start..end {
            if result[i] > result[i + 1] {
                result.swap(i, i + 1);
                swapped = true;
            }
        }

        if !swapped {
            break;
        }

        swapped = false;
        end -= 1;

        // Backward pass
        for i in (start..end).rev() {
            if result[i] > result[i + 1] {
                result.swap(i, i + 1);
                swapped = true;
            }
        }

        start += 1;
    }

    result
}

package algorithms.sorting.cocktail

/**
 * Cocktail Sort implementation.
 * Repeatedly steps through the list in both directions, comparing adjacent elements 
 * and swapping them if they are in the wrong order.
 */
object CocktailSort {
  def sort(arr: Array[Int]): Array[Int] = {
    if (arr.length <= 1) {
      return arr.clone()
    }

    val result = arr.clone()
    val n = result.length
    var start = 0
    var end = n - 1
    var swapped = true

    while (swapped) {
      swapped = false

      // Forward pass
      for (i <- start until end) {
        if (result(i) > result(i + 1)) {
          val temp = result(i)
          result(i) = result(i + 1)
          result(i + 1) = temp
          swapped = true
        }
      }

      if (!swapped) {
        // Break using return
        return result
      }

      swapped = false
      end -= 1

      // Backward pass
      for (i <- (end - 1) to start by -1) {
        if (result(i) > result(i + 1)) {
          val temp = result(i)
          result(i) = result(i + 1)
          result(i + 1) = temp
          swapped = true
        }
      }

      start += 1
    }

    result
  }
}

/**
 * Cocktail Sort implementation.
 * Repeatedly steps through the list in both directions, comparing adjacent elements 
 * and swapping them if they are in the wrong order.
 */
public class CocktailSort {
    public static func sort(_ arr: [Int]) -> [Int] {
        if arr.count <= 1 {
            return arr
        }

        var result = arr
        let n = result.count
        var start = 0
        var end = n - 1
        var swapped = true

        while swapped {
            swapped = false

            // Forward pass
            for i in start..<end {
                if result[i] > result[i + 1] {
                    result.swapAt(i, i + 1)
                    swapped = true
                }
            }

            if !swapped {
                break
            }

            swapped = false
            end -= 1

            // Backward pass
            for i in stride(from: end - 1, through: start, by: -1) {
                if result[i] > result[i + 1] {
                    result.swapAt(i, i + 1)
                    swapped = true
                }
            }

            start += 1
        }

        return result
    }
}

/**
 * Cocktail Sort (Bidirectional Bubble Sort) implementation.
 * Repeatedly steps through the list in both directions, comparing adjacent elements 
 * and swapping them if they are in the wrong order.
 * @param arr the input array
 * @returns a sorted copy of the array
 */
export function cocktailSort(arr: number[]): number[] {
    const result = [...arr];
    const n = result.length;
    if (n <= 1) {
        return result;
    }

    let start = 0;
    let end = n - 1;
    let swapped = true;

    while (swapped) {
        swapped = false;

        // Forward pass
        for (let i = start; i < end; i++) {
            if (result[i] > result[i + 1]) {
                [result[i], result[i + 1]] = [result[i + 1], result[i]];
                swapped = true;
            }
        }

        if (!swapped) {
            break;
        }

        swapped = false;
        end--;

        // Backward pass
        for (let i = end - 1; i >= start; i--) {
            if (result[i] > result[i + 1]) {
                [result[i], result[i + 1]] = [result[i + 1], result[i]];
                swapped = true;
            }
        }

        start++;
    }

    return result;
}
